# =============================================================================
# src/evaluation/image_drift_analysis.py — Model sensitivity analysis
# =============================================================================
# Evaluates the trained model on all ISP drift scenarios (generated by
# image_drift_simulator.py) and produces a sensitivity report showing how
# model performance changes across different ISP parameter variations.
#
# This is the offline sensitivity profiling step. It runs after
# drift simulation and answers: "how sensitive is this model to each type
# of ISP change?"
#
# Split consistency
# -----------------
# Baseline metrics come from evaluation_report.json, which evaluate.py
# computes on the val split (val.npz). Each scenario is also evaluated on
# its val.npz. Both use the same split, so delta metrics are directly
# comparable. The split name is recorded in the report for auditability.
#
# Model type scope
# ----------------
# This module supports image_classification_cnn only:
#   PyTorch .pt model; NPZ shape is (N, H, W, C), transposed to (N, C, H, W)
#   before calling model.predict(). 
#
# Sensitivity thresholds
# ----------------------
# Classification by absolute accuracy drop (percentage points):
#   high:   drop ≥ high_threshold   (default 0.15 = 15 pp)
#   medium: drop ≥ medium_threshold (default 0.05 = 5 pp)
#   low:    drop < medium_threshold
#
# Thresholds are passed as a parameter so callers can configure them without
# touching this module. Defaults are documented in DEFAULT_SENSITIVITY_THRESHOLDS.
#
# Output:
#   drift_scenarios/sensitivity_report.json  — machine-readable full report
#   drift_scenarios/sensitivity_report.html  — human-readable summary table
#
# The caller (_run_image_drift_stage in steps.py) handles MLflow logging,
# so this module has no MLflow dependency.
# =============================================================================

from __future__ import annotations

import json
import logging
from datetime import datetime, timezone
from pathlib import Path

import numpy as np

from src.common.io import atomic_write_json

logger = logging.getLogger(__name__)

# Default thresholds for classifying accuracy drop into sensitivity severity.
# Pass a custom dict to run_sensitivity_analysis() to override these.
DEFAULT_SENSITIVITY_THRESHOLDS: dict[str, float] = {
    "high":   0.15,   # accuracy drop >= 15 percentage points
    "medium": 0.05,   # accuracy drop >= 5 percentage points
}

# Split used for both baseline and scenario evaluation. Must match the split
# that evaluate.py uses for image tasks (currently "val").
_EVALUATION_SPLIT = "val"


# =============================================================================
# Public API
# =============================================================================

def run_sensitivity_analysis(
    version_id: str,
    task_type: str,
    drift_scenarios_dir: Path,
    artifact_dir: Path = Path("artifacts/runs"),
    baseline_report_path: Path | None = None,
    sensitivity_thresholds: dict[str, float] | None = None,
) -> dict:
    """Evaluate the trained model on all drift scenarios and build a sensitivity report.

    Both baseline and scenario metrics are measured on the val split (val.npz),
    so delta values are directly comparable. The split name is recorded in the
    report for auditability.

    Args:
        version_id:              Dataset/run version hash (locates the model artifact).
        task_type:               Pipeline task type. Must be "image_classification_cnn"
                                 (PyTorch CNN, .pt artifact). NPZ shape (N, H, W, C)
                                 is transposed to (N, C, H, W) before inference.
        drift_scenarios_dir:     Root directory containing scenario subdirectories
                                 (each with val.npz and scenario_metadata.json).
        artifact_dir:            Base directory for model artifacts.
        baseline_report_path:    Path to evaluation_report.json written by
                                 _evaluation_stage. When present, delta metrics
                                 (Δ accuracy, Δ F1) are computed. Baseline metrics
                                 in that report are from the val split — same as
                                 scenario evaluation — so deltas are valid.
        sensitivity_thresholds:  Dict with keys "high" and "medium" (float, 0–1).
                                 Defaults to DEFAULT_SENSITIVITY_THRESHOLDS.

    Returns:
        Sensitivity report dict. Saved to disk by the caller.

    Raises:
        FileNotFoundError: If the model artifact is missing.
        ValueError: If no scenario directories are found, or all scenarios fail.
    """
    thresholds = sensitivity_thresholds or DEFAULT_SENSITIVITY_THRESHOLDS

    drift_scenarios_dir = Path(drift_scenarios_dir)

    # --- Load trained model ---
    model = _load_model(version_id, artifact_dir, task_type)

    # --- Load baseline metrics from evaluation report (if available) ---
    # evaluation_report.json is produced by _evaluation_stage, which calls
    # evaluate.py. For image tasks, evaluate.py loads val.npz — the same
    # split used here. This guarantees baseline and scenario metrics are comparable.
    baseline_metrics: dict | None = None
    if baseline_report_path and Path(baseline_report_path).exists():
        with open(baseline_report_path) as f:
            eval_report = json.load(f)
        baseline_metrics = eval_report.get("metrics")
        logger.info(
            "  Baseline metrics (%s split) — accuracy=%.4f, f1=%.4f",
            _EVALUATION_SPLIT,
            baseline_metrics.get("accuracy", float("nan")),
            baseline_metrics.get("f1_score", float("nan")),
        )
    else:
        logger.warning(
            "  No baseline evaluation report found — delta metrics will be omitted. "
            "Run the evaluation stage before drift analysis to enable delta computation."
        )

    # --- Discover scenario directories ---
    scenario_dirs = sorted(
        d for d in drift_scenarios_dir.iterdir()
        if d.is_dir() and (d / "scenario_metadata.json").exists()
    )
    if not scenario_dirs:
        raise ValueError(
            f"No scenario directories found under '{drift_scenarios_dir}'. "
            "Run drift simulation before sensitivity analysis."
        )

    # --- Evaluate model on each scenario ---
    scenario_results: list[dict] = []
    for scenario_dir in scenario_dirs:
        result = _evaluate_scenario(
            scenario_dir, model, task_type, baseline_metrics, thresholds
        )
        if result is not None:
            scenario_results.append(result)
            filtered = result.get("filtered_count", 0)
            filter_note = f"  ({filtered} filtered)" if filtered else ""
            logger.info(
                "  Scenario '%s': accuracy=%.4f  f1=%.4f  Δacc=%+.4f  "
                "sensitivity=%s  [evaluated=%d%s]",
                result["name"],
                result["metrics"]["accuracy"],
                result["metrics"]["f1_score"],
                result["delta"].get("accuracy", float("nan")),
                result["sensitivity"],
                result["evaluated_count"],
                filter_note,
            )

    if not scenario_results:
        raise ValueError("All scenarios failed evaluation — check the scenario NPZ files.")

    # --- Identify most / least sensitive scenarios (by |Δ accuracy|) ---
    ranked = sorted(
        scenario_results,
        key=lambda r: abs(r["delta"].get("accuracy", 0.0)),
        reverse=True,
    )
    most_sensitive = ranked[0]["name"]
    least_sensitive = ranked[-1]["name"]

    report = {
        "schema_version": "1.0.0",
        "report_type": "image_isp_sensitivity",
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "task_type": task_type,
        "version_id": version_id,
        "evaluation_split": _EVALUATION_SPLIT,
        "baseline_metrics": baseline_metrics,
        "sensitivity_thresholds": thresholds,
        "scenarios": scenario_results,
        "most_sensitive_scenario": most_sensitive,
        "least_sensitive_scenario": least_sensitive,
        "scenario_count": len(scenario_results),
    }

    logger.info(
        "  Sensitivity analysis complete: %d scenarios — "
        "most sensitive: '%s', least: '%s'",
        len(scenario_results), most_sensitive, least_sensitive,
    )
    return report


def save_sensitivity_report_json(report: dict, output_dir: Path) -> Path:
    """Persist the sensitivity report as JSON.

    Args:
        report:     Sensitivity report dict from run_sensitivity_analysis().
        output_dir: Directory to write into (created if missing).

    Returns:
        Path to the written file.
    """
    path = Path(output_dir) / "sensitivity_report.json"
    atomic_write_json(path, report)
    return path


def save_sensitivity_report_html(report: dict, output_dir: Path) -> Path:
    """Render and save the sensitivity report as a self-contained HTML file.

    Args:
        report:     Sensitivity report dict from run_sensitivity_analysis().
        output_dir: Directory to write into (created if missing).

    Returns:
        Path to the written file.
    """
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    html = _render_html_report(report)
    path = output_dir / "sensitivity_report.html"
    path.write_text(html, encoding="utf-8")
    return path


# =============================================================================
# Private helpers
# =============================================================================

def _load_model(version_id: str, artifact_dir: Path, task_type: str):
    """Load the trained PyTorch CNN model artifact.

    Args:
        version_id:   Version hash used to locate the model directory.
        artifact_dir: Base directory for model artifacts.
        task_type:    Logged for context; must be "image_classification_cnn".

    Returns:
        Loaded PyTorch model with a `.predict(X)` method.

    Raises:
        FileNotFoundError: If model.pt is not found in the model directory.
    """
    model_dir = Path(artifact_dir) / version_id / "model"
    pt_path = model_dir / "model.pt"

    if pt_path.exists():
        import torch
        logger.debug("  Loading PyTorch model from %s (task_type=%s)", pt_path, task_type)
        return torch.load(pt_path, weights_only=False, map_location="cpu")

    raise FileNotFoundError(
        f"Model artifact not found at '{model_dir}'. "
        "Run the training stage before sensitivity analysis. "
        "Expected: model.pt (image_classification_cnn)."
    )


def _evaluate_scenario(
    scenario_dir: Path,
    model,
    task_type: str,
    baseline_metrics: dict | None,
    thresholds: dict[str, float],
) -> dict | None:
    """Evaluate the model on a single scenario's val split.

    Uses val.npz — the same split as evaluate.py — so metrics are directly
    comparable to the baseline in evaluation_report.json.

    Args:
        scenario_dir:     Directory containing val.npz and scenario_metadata.json.
        model:            Trained PyTorch CNN with a .predict() method.
        task_type:        Must be "image_classification_cnn". NPZ arrays are
                          (N, H, W, C) and transposed to (N, C, H, W) before inference.
        baseline_metrics: Metrics from evaluation_report.json (val split), or None.
        thresholds:       Sensitivity classification thresholds.

    Returns:
        Scenario result dict, or None if the val split is missing or evaluation fails.
    """
    val_npz = scenario_dir / f"{_EVALUATION_SPLIT}.npz"
    meta_path = scenario_dir / "scenario_metadata.json"

    if not val_npz.exists():
        logger.warning(
            "  Scenario '%s': %s.npz not found — skipping",
            scenario_dir.name, _EVALUATION_SPLIT,
        )
        return None

    with open(meta_path) as f:
        metadata = json.load(f)

    try:
        data = np.load(val_npz)
        X, y_true = data["X"], data["y"]
        total_count = int(len(X))
        evaluated_count = total_count
        filtered_count = 0

        if evaluated_count == 0:
            logger.error("  Scenario '%s': val split is empty — skipping", metadata["scenario_name"])
            return None

        # Transpose from NPZ storage format (N, H, W, C) to PyTorch format (N, C, H, W).
        if X.ndim == 4:
            X = X.transpose(0, 3, 1, 2)

        y_pred = model.predict(X)
        metrics = _compute_scenario_metrics(y_true, y_pred)

    except Exception as e:
        logger.error(
            "  Scenario '%s': evaluation failed: %s",
            scenario_dir.name, e, exc_info=True,
        )
        return None

    # --- Compute delta vs baseline (both on val split) ---
    delta: dict[str, float] = {}
    if baseline_metrics:
        for key in ("accuracy", "f1_score"):
            if key in metrics and key in baseline_metrics:
                delta[key] = round(metrics[key] - baseline_metrics[key], 4)

    # --- Classify sensitivity from |Δ accuracy| ---
    acc_drop = abs(delta.get("accuracy", 0.0))
    sensitivity = _classify_sensitivity(acc_drop, thresholds)

    return {
        "name": metadata["scenario_name"],
        "description": metadata.get("description", ""),
        "isp_overrides": metadata.get("isp_overrides", {}),
        "total_count": total_count,
        "filtered_count": filtered_count,
        "evaluated_count": evaluated_count,
        "metrics": metrics,
        "delta": delta,
        "sensitivity": sensitivity,
    }


def _compute_scenario_metrics(y_true: np.ndarray, y_pred: np.ndarray) -> dict:
    """Compute accuracy and weighted F1 for a scenario evaluation.

    Args:
        y_true: Ground-truth class indices (int).
        y_pred: Model-predicted class indices (int).

    Returns:
        Dict with "accuracy" and "f1_score", rounded to 4 decimal places.
    """
    from sklearn.metrics import accuracy_score, f1_score

    return {
        "accuracy": round(float(accuracy_score(y_true, y_pred)), 4),
        "f1_score": round(
            float(f1_score(y_true, y_pred, average="weighted", zero_division=0)), 4
        ),
    }


def _classify_sensitivity(
    accuracy_drop: float,
    thresholds: dict[str, float],
) -> str:
    """Map an absolute accuracy drop to a sensitivity severity label.

    Args:
        accuracy_drop: Absolute accuracy change (positive = drop from baseline).
        thresholds:    Dict with "high" and "medium" float thresholds.

    Returns:
        "high", "medium", or "low".
    """
    if accuracy_drop >= thresholds.get("high", DEFAULT_SENSITIVITY_THRESHOLDS["high"]):
        return "high"
    if accuracy_drop >= thresholds.get("medium", DEFAULT_SENSITIVITY_THRESHOLDS["medium"]):
        return "medium"
    return "low"


def _render_html_report(report: dict) -> str:
    """Render the sensitivity report as a self-contained HTML page.

    Produces a table with scenario name, ISP changes, accuracy, F1,
    delta metrics, image counts (including filtered), and sensitivity
    classification. No external dependencies — pure string interpolation.

    Args:
        report: Sensitivity report dict from run_sensitivity_analysis().

    Returns:
        HTML string.
    """
    generated_at = report.get("generated_at", "")[:19].replace("T", " ")
    task_type = report.get("task_type", "")
    version_id = report.get("version_id", "")
    eval_split = report.get("evaluation_split", _EVALUATION_SPLIT)
    baseline = report.get("baseline_metrics") or {}
    scenarios = report.get("scenarios", [])
    most_sensitive = report.get("most_sensitive_scenario", "—")
    least_sensitive = report.get("least_sensitive_scenario", "—")
    thresholds = report.get("sensitivity_thresholds", DEFAULT_SENSITIVITY_THRESHOLDS)

    high_pct = int(thresholds.get("high", 0.15) * 100)
    medium_pct = int(thresholds.get("medium", 0.05) * 100)

    def _fmt_metric(val) -> str:
        return f"{val:.4f}" if isinstance(val, float) else "N/A"

    baseline_acc = _fmt_metric(baseline.get("accuracy"))
    baseline_f1 = _fmt_metric(baseline.get("f1_score"))

    _SEVERITY_COLORS = {
        "high":   "#d9534f",
        "medium": "#f0ad4e",
        "low":    "#5cb85c",
    }

    def _fmt_isp(overrides: dict) -> str:
        parts = []
        for section, params in overrides.items():
            if isinstance(params, dict):
                for k, v in params.items():
                    parts.append(f"{section}.{k}={v}")
            else:
                parts.append(f"{section}={params}")
        return "<br>".join(parts) if parts else "—"

    def _fmt_delta(delta: dict, key: str) -> str:
        v = delta.get(key)
        if v is None:
            return "N/A"
        sign = "+" if v >= 0 else ""
        return f"{sign}{v:.4f}"

    def _fmt_counts(s: dict) -> str:
        total = s.get("total_count", s.get("evaluated_count", "?"))
        filtered = s.get("filtered_count", 0)
        evaluated = s.get("evaluated_count", total)
        if filtered:
            return f'{evaluated} <span style="color:#c0392b" title="{filtered} excluded (unknown class)">(−{filtered})</span>'
        return str(evaluated)

    rows = ""
    for s in scenarios:
        sev = s.get("sensitivity", "low")
        color = _SEVERITY_COLORS.get(sev, "#888")
        rows += f"""
        <tr>
          <td><strong>{s['name']}</strong></td>
          <td style="font-size:0.85em; color:#555">{_fmt_isp(s.get('isp_overrides', {}))}</td>
          <td>{_fmt_counts(s)}</td>
          <td>{_fmt_metric(s['metrics'].get('accuracy'))}</td>
          <td>{_fmt_metric(s['metrics'].get('f1_score'))}</td>
          <td>{_fmt_delta(s.get('delta', {}), 'accuracy')}</td>
          <td>{_fmt_delta(s.get('delta', {}), 'f1_score')}</td>
          <td style="color:{color}; font-weight:bold">{sev.upper()}</td>
          <td style="color:#555; font-size:0.85em">{s.get('description', '')}</td>
        </tr>"""

    return f"""<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>ISP Sensitivity Report — {version_id[:8]}</title>
  <style>
    body {{ font-family: Arial, sans-serif; margin: 2em; color: #333; }}
    h1   {{ color: #2c3e50; }}
    h2   {{ color: #34495e; margin-top: 1.5em; }}
    .meta  {{ background: #f8f9fa; padding: 1em; border-radius: 4px; margin-bottom: 1.5em; }}
    .meta span {{ margin-right: 2em; }}
    .summary {{ background: #eef2ff; padding: 0.8em 1.2em; border-left: 4px solid #4a6cf7;
                border-radius: 4px; margin-bottom: 1.5em; }}
    table {{ border-collapse: collapse; width: 100%; }}
    th, td {{ border: 1px solid #ddd; padding: 8px 12px; text-align: left; }}
    th {{ background: #2c3e50; color: white; }}
    tr:nth-child(even) {{ background: #f8f9fa; }}
    tr:hover {{ background: #eef2ff; }}
    .note {{ color: #888; font-size: 0.85em; margin-top: 1em; }}
  </style>
</head>
<body>
  <h1>ISP Drift Sensitivity Report</h1>

  <div class="meta">
    <span><strong>Task type:</strong> {task_type}</span>
    <span><strong>Version:</strong> {version_id[:12]}</span>
    <span><strong>Evaluation split:</strong> {eval_split}</span>
    <span><strong>Generated:</strong> {generated_at} UTC</span>
    <span><strong>Scenarios:</strong> {len(scenarios)}</span>
  </div>

  <div class="summary">
    <strong>Baseline ({eval_split} split)</strong> — accuracy: {baseline_acc}, F1: {baseline_f1}<br>
    <strong>Most sensitive scenario:</strong> {most_sensitive} &nbsp;|&nbsp;
    <strong>Least sensitive:</strong> {least_sensitive}
  </div>

  <h2>Scenario Results</h2>
  <p class="note">
    Sensitivity classified by absolute accuracy drop (vs baseline {eval_split} split):
    HIGH ≥ {high_pct} pp &nbsp;|&nbsp; MEDIUM ≥ {medium_pct} pp &nbsp;|&nbsp; LOW &lt; {medium_pct} pp.<br>
    <em>Images</em> column shows evaluated count. Red (−N) indicates images excluded due to unknown class labels.
    Baseline and scenario metrics both use the <strong>{eval_split}</strong> split for valid comparison.
  </p>

  <table>
    <thead>
      <tr>
        <th>Scenario</th>
        <th>ISP Changes</th>
        <th>Images</th>
        <th>Accuracy</th>
        <th>F1 Score</th>
        <th>Δ Accuracy</th>
        <th>Δ F1</th>
        <th>Sensitivity</th>
        <th>Description</th>
      </tr>
    </thead>
    <tbody>
      {rows}
    </tbody>
  </table>

  <p class="note">
    Report type: ISP-based drift simulation (raw_input: true).
    Delta metrics require a baseline evaluation_report.json to be present.
    This analysis applies only to image models evaluated via their {eval_split} split NPZ files.
  </p>
</body>
</html>
"""
